action.command:
node -e "
const fs = require('fs');
const input = fs.readFileSync(0, 'utf8');
const data = JSON.parse(input);

// Solo validar si el archivo destino es un workflow de GitHub Actions
const path = data.tool_input && (data.tool_input.path || '');
if (!path.includes('.github/workflows/')) {
  process.exit(0);
}

// Obtener el contenido que se va a escribir
const content = data.tool_input.text || data.tool_input.newStr || data.tool_input.content || '';

// Verificar si incluye un step de tests (npm test, jest, run: test, etc.)
const hasTestStep = /npm(\s+run\s+)?\s*test|jest|yarn\s+test|run:\s*(npm\s+test|jest|yarn\s+test)/.test(content);

if (!hasTestStep) {
  console.error('ERROR: El workflow no incluye un step de pruebas (tests).');
  console.error('Segun los estandares del equipo, todos los workflows deben incluir lint, test y build.');
  console.error('Agrega un job o step que ejecute: npm test (o equivalente con Jest).');
  process.exit(2);
}

process.exit(0);
"
